// Best config per (m, n, k) shape (top-1 by GB prediction)
struct ShapeKey {
    int m, n, k;
    bool operator==(const ShapeKey& o) const {
        return m == o.m && n == o.n && k == o.k;
    }
};

struct ShapeKeyHash {
    size_t operator()(const ShapeKey& k) const {
        return std::hash<int>()(k.m) ^ 
               (std::hash<int>()(k.n) << 1) ^ 
               (std::hash<int>()(k.k) << 2);
    }
};

